member.example:
Bind the AudioSource clip using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView : MonoView
    {
        [SerializeField]
        private AudioSourceClipBinder _clip;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public AudioClip _clip;
    }


Bind the AudioSource clip by constructing the binder in code.

    [View]
    public partial class ExampleView : MonoView
    {
        [SerializeField]
        private AudioSource _audioSource;
        
        private AudioSourceClipBinder Clip =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public AudioClip _clip;
    }

Switch the AudioSource clip using a serialized binder field — clips and the target AudioSource are assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceClipSwitcherBinder _isPlaying;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPlaying;
    }


Switch the AudioSource clip between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private AudioClip _trueClip;
        
        [SerializeField]
        private AudioClip _falseClip;
        
        private AudioSourceClipSwitcherBinder IsPlaying => new(
            _audioSource, _trueClip, _falseClip);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPlaying;
    }
